225	// supersedingTargetID returns the ID of the bead that supersedes b, either
226	// from the canonical `superseded-by` extra field or from a
227	// `superseded-by:<id>` label. Empty string means not superseded.
228	func supersedingTargetID(b Bead) string {
229		if id := lifecycleSupersededBy(b); id != "" {
230			return id
231		}
232		for _, l := range b.Labels {
233			if strings.HasPrefix(l, "superseded-by:") {
234				if id := strings.TrimSpace(strings.TrimPrefix(l, "superseded-by:")); id != "" {
235					return id
236				}
237			}
238		}
239		return ""
240	}
241	
242	// lookupBead scans the childIndex (which holds every bead, keyed by parent
243	// ID with roots under "") for the bead with the given ID.
244	func lookupBead(childIndex map[string][]Bead, id string) (Bead, bool) {
245		if id == "" {
246			return Bead{}, false
247		}
248		for _, beads := range childIndex {
249			for _, b := range beads {
250				if b.ID == id {
251					return b, true
252				}
253			}
254		}
255		return Bead{}, false
256	}
257	
258	func beadIDsFrom(beads []Bead) []string {
259		out := make([]string, 0, len(beads))
260		for _, b := range beads {
261			out = append(out, b.ID)
262		}
263		sort.Strings(out)
264		return out
265	}
