320	// parentChildConflict detects state mismatches the classifier does not
321	// expect: e.g., a child whose parent is closed while the child is open and
322	// not eligible, or a bead that is itself closed but appears in the
323	// open-child index for its parent.
324	func parentChildConflict(b Bead, childIndex map[string][]Bead) string {
325		if b.Parent == "" {
326			return ""
327		}
328		parent, ok := lookupBead(childIndex, b.Parent)
329		if !ok {
330			return ""
331		}
332		if b.Status == StatusClosed && parent.Status != StatusClosed {
333			eligible, set := lifecycleExecutionEligible(parent)
334			parentMarkedDead := set && !eligible
335			if !parentMarkedDead {
336				return fmt.Sprintf("child %s closed but parent %s open and execution-eligible", b.ID, parent.ID)
337			}
338		}
339		if b.Status == StatusInProgress && parent.Status == StatusClosed {
340			return fmt.Sprintf("bead %s in_progress but parent %s already closed", b.ID, parent.ID)
341		}
342		return ""
343	}
