345	func isProviderRouteUnavailable(b Bead) bool {
346		last := extraStringVal(b.Extra, ExtraLastStatus)
347		detail := extraStringVal(b.Extra, ExtraLastDetail)
348		if strings.Contains(strings.ToLower(last), "no live provider") {
349			return true
350		}
351		if strings.Contains(strings.ToLower(detail), "no live provider") {
352			return true
353		}
354		if strings.Contains(detail, "ResolveRoute:") {
355			return true
356		}
357		return false
358	}
