367	// budgetOrCooldownGate returns a non-empty descriptor when a retry-after
368	// cooldown or auto-remediation budget gate is recorded on the bead.
369	func budgetOrCooldownGate(b Bead) string {
370		if v := extraStringVal(b.Extra, ExtraRetryAfter); v != "" {
371			return "retry-after cooldown active until " + v
372		}
373		if v := extraStringVal(b.Extra, "auto-remediation-gate"); v != "" {
374			return "auto-remediation gated: " + v
375		}
376		return ""
377	}
