379	func malformedRef(b Bead, childIndex map[string][]Bead) (string, []string) {
380		if b.Parent != "" {
381			if _, ok := lookupBead(childIndex, b.Parent); !ok {
382				return fmt.Sprintf("parent %q does not resolve in index", b.Parent), []string{b.Parent}
383			}
384		}
385		for _, d := range b.Dependencies {
386			if strings.TrimSpace(d.DependsOnID) == "" {
