440	// staleIndexDisagreement reports when childIndex and openChildIndex are
441	// inconsistent for b: an entry appears in openChildIndex but its Status is
442	// closed/cancelled, or an open child in childIndex is missing from the
443	// open-child bucket.
444	func staleIndexDisagreement(b Bead, childIndex, openChildIndex map[string][]Bead) string {
445		open := openChildIndex[b.ID]
446		all := childIndex[b.ID]
447		for _, c := range open {
448			if c.Status == StatusClosed || c.Status == StatusCancelled {
449				return fmt.Sprintf("open-child index lists %s with closed status", c.ID)
450			}
451		}
452		openIDs := map[string]bool{}
453		for _, c := range open {
454			openIDs[c.ID] = true
455		}
456		for _, c := range all {
457			isOpenStatus := c.Status != StatusClosed && c.Status != StatusCancelled
458			if isOpenStatus && !openIDs[c.ID] {
459				return fmt.Sprintf("child %s has open status but missing from open-child index", c.ID)
460			}
461		}
462		return ""
463	}
