465	func isAutoRemediationExhausted(b Bead) bool {
466		if extraStringVal(b.Extra, "auto-remediation-exhausted") == "true" {
467			return true
468		}
469		for _, l := range b.Labels {
470			if l == "auto-remediation:exhausted" {
471				return true
472			}
473		}
474		return false
475	}
