2375	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
2376		out := ReadyExecutionBreakdown{}
2377		beads, err := s.ReadAll(context.Background())
2378		if err != nil {
2379			return out, err
2380		}
2381		now := time.Now().UTC()
2382		var soonestRetry time.Time
2383		for _, entry := range s.classifyLifecycleQueue(beads, now) {
2384			switch entry.Decision.Bucket {
2385			case LifecycleBucketReady:
2386				out.ExecutionReady = append(out.ExecutionReady, entry.ID)
2387			case LifecycleBucketWaitingDependencies:
2388				out.DependencyWaiting = append(out.DependencyWaiting, entry.ID)
2389			case LifecycleBucketRetryCooldown:
2390				out.RetryCooldown = append(out.RetryCooldown, entry.ID)
2391				if !entry.RetryAfter.IsZero() && (soonestRetry.IsZero() || entry.RetryAfter.Before(soonestRetry)) {
2392					soonestRetry = entry.RetryAfter
2393				}
2394			case LifecycleBucketEpicContainer:
2395				if entry.EpicClosureCandidate {
2396					out.EpicClosureCandidates = append(out.EpicClosureCandidates, entry.ID)
2397				} else {
2398					out.Epics = append(out.Epics, entry.ID)
2399				}
2400			case LifecycleBucketNotEligible:
2401				out.NotEligible = append(out.NotEligible, entry.ID)
2402			case LifecycleBucketSuperseded:
2403				out.Superseded = append(out.Superseded, entry.ID)
2404			case LifecycleBucketBlockedExternal:
2405				out.ExternalBlocked = append(out.ExternalBlocked, entry.ID)
2406			case LifecycleBucketProposed:
2407				out.ProposedOperatorAttention = append(out.ProposedOperatorAttention, entry.ID)
2408			}
2409		}
2410		if !soonestRetry.IsZero() {
2411			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
2412		}
2413		out.HumanReviewBlockers, out.HumanReviewBlockedTotal = humanReviewBlockerPressure(beads)
2414		return out, nil
2415	}
