223	// validateEpicDescription checks that the description contains PROBLEM, PROPOSED FIX,
224	// at least one numbered AC, and at least one spec:/area: label.
225	func validateEpicDescription(b *bead.Bead) error {
226		desc := strings.TrimSpace(b.Description)
227		if desc == "" {
228			return fmt.Errorf("empty description")
229		}
230		if !strings.Contains(desc, "PROBLEM") {
231			return fmt.Errorf("missing PROBLEM section")
232		}
233		if !strings.Contains(desc, "PROPOSED FIX") {
234			return fmt.Errorf("missing PROPOSED FIX section")
235		}
236	
237		// Check for at least one numbered AC (1. pattern)
238		hasAC := false
239		acLines := strings.Split(b.Acceptance, "\n")
240		for _, line := range acLines {
241			trimmed := strings.TrimSpace(line)
242			if strings.HasPrefix(trimmed, "1.") {
243				hasAC = true
244				break
245			}
246		}
247		if !hasAC {
248			return fmt.Errorf("missing numbered acceptance criteria")
249		}
250	
251		// Check for at least one spec:/area: label
252		hasSpecOrArea := false
253		for _, label := range b.Labels {
254			if strings.HasPrefix(label, "spec:") || strings.HasPrefix(label, "area:") {
255				hasSpecOrArea = true
256				break
257			}
258		}
259		if !hasSpecOrArea {
260			return fmt.Errorf("missing spec: or area: label")
261		}
262	
263		return nil
264	}
