295	// hasActiveCooldown checks if the bead has a retry-after cooldown that is still active.
296	func hasActiveCooldown(b *bead.Bead) bool {
297		retryAfterStr := extraStringValFromExtra(b.Extra, bead.ExtraRetryAfter)
298		if retryAfterStr == "" {
299			return false
300		}
301		retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
302		if err != nil {
303			return false
304		}
305		return retryAfter.After(time.Now().UTC())
306	}
