333	// getAllBeads fetches all beads from the store via ReadyExecution().
334	func getAllBeads(store ExecuteBeadLoopStore, ctx context.Context) []bead.Bead {
335		readyBeads, err := store.ReadyExecution()
336		if err == nil && len(readyBeads) > 0 {
337			return readyBeads
338		}
339		// Fallback: return empty slice if ReadyExecution fails
340		return []bead.Bead{}
341	}
