343	// buildChildIndex builds a child index from all beads.
344	// This is used by Diagnose; beads are keyed by parent ID with roots under "".
345	func buildChildIndex(beads []bead.Bead) map[string][]bead.Bead {
346		index := make(map[string][]bead.Bead)
347		for _, b := range beads {
348			parent := b.Parent
349			if parent == "" {
350				parent = ""
351			}
352			index[parent] = append(index[parent], b)
353		}
354		// Ensure roots are in the index
355		index[""] = append(index[""], beads...)
356		return index
357	}
358	
359	// buildOpenChildIndex builds an open-child index from all beads.
360	// Only beads with open status are included.
361	func buildOpenChildIndex(beads []bead.Bead) map[string][]bead.Bead {
362		index := make(map[string][]bead.Bead)
363		for _, b := range beads {
364			if b.Status == bead.StatusClosed || b.Status == bead.StatusCancelled {
365				continue
366			}
367			parent := b.Parent
368			if parent == "" {
369				parent = ""
370			}
371			index[parent] = append(index[parent], b)
372		}
373		return index
374	}
375	
376	// buildDepIndex builds a dependency index from all beads.
377	// Maps bead_id -> outgoing Dependency entries.
378	func buildDepIndex(beads []bead.Bead) map[string][]bead.Dependency {
379		index := make(map[string][]bead.Dependency)
380		for _, b := range beads {
381			index[b.ID] = append(index[b.ID], b.Dependencies...)
382		}
383		return index
384	}
