165	func (f *CommandFactory) runAgentExecuteLoopImpl(cmd *cobra.Command, treatPassthroughAsOpaque bool, tryTargetBeadID string) error {
166		spec, dispatch, err := parseExecuteLoopSpec(cmd, treatPassthroughAsOpaque)
167		if err != nil {
168			return err
169		}
170		projectRoot := resolveProjectRoot(spec.ProjectRoot, f.WorkingDir)
171		spec.ProjectRoot = projectRoot
172		if tryTargetBeadID != "" {
173			spec.Mode = executeloop.ModeOnce
174			spec.IdleInterval = executeloop.Duration{}
175		}
176	
177		noRoutingFlags := spec.Harness == "" && spec.Model == "" && spec.Provider == "" &&
178			spec.Profile == "" && spec.MinPower == 0 &&
179			spec.MaxPower == 0 && !cmd.Flags().Changed("harness") &&
180			!cmd.Flags().Changed("model") && !cmd.Flags().Changed("provider") &&
