631	func worktreeStillLive(meta agent.ExecutionCleanupMetadata, runStates []agent.RunState, now time.Time) bool {
632		if meta.Preserved || meta.ActiveCandidateCycle || strings.TrimSpace(meta.CandidateRef) != "" {
633			return true
634		}
635		if worktreeLivenessAlive(meta.Liveness, now) {
636			return true
637		}
638		for _, state := range runStates {
639			if !runStateMatchesWorktree(state, meta) {
640				continue
641			}
642			if strings.TrimSpace(state.CandidateCyclePhase) != "" || strings.TrimSpace(state.CandidateRef) != "" {
643				return true
644			}
645			if worktreeRunStateAlive(state, now) {
646				return true
647			}
648		}
649		return false
650	}
651	
652	func worktreeLivenessAlive(liveness *agent.ExecutionCleanupLiveness, now time.Time) bool {
653		if liveness == nil {
654			return false
655		}
656		if processAlive(liveness.PID) {
657			return true
658		}
659		if !liveness.ExpiresAt.IsZero() && now.Before(liveness.ExpiresAt) {
660			return true
661		}
662		return !liveness.RefreshedAt.IsZero() && now.Sub(liveness.RefreshedAt) <= 2*time.Minute
663	}
664	
665	func worktreeRunStateAlive(state agent.RunState, now time.Time) bool {
666		if processAlive(state.PID) {
667			return true
668		}
669		if !state.ExpiresAt.IsZero() && now.Before(state.ExpiresAt) {
670			return true
671		}
672		return !state.RefreshedAt.IsZero() && now.Sub(state.RefreshedAt) <= agent.RunStateLivenessTTL
673	}
674	
675	func runStateMatchesWorktree(state agent.RunState, meta agent.ExecutionCleanupMetadata) bool {
676		if meta.AttemptID != "" && state.AttemptID == meta.AttemptID {
677			return true
678		}
679		return meta.WorktreePath != "" &&
680			state.WorktreePath != "" &&
681			filepath.Clean(state.WorktreePath) == filepath.Clean(meta.WorktreePath)
682	}
683	
684	func processAlive(pid int) bool {
685		if pid <= 0 {
686			return false
687		}
688		proc, err := os.FindProcess(pid)
689		if err != nil {
690			return false
691		}
692		return proc.Signal(syscall.Signal(0)) == nil
693	}
694	
695	func firstNonEmpty(values ...string) string {
696		for _, value := range values {
697			if strings.TrimSpace(value) != "" {
698				return value
699			}
700		}
701		return ""
702	}
703	
704	func worktreeReapMaxAgeFromEnv() time.Duration {
705		raw := strings.TrimSpace(os.Getenv("DDX_WORKTREE_REAP_MAX_AGE"))
706		if raw == "" {
707			return defaultWorktreeReapMaxAge
708		}
709		d, err := time.ParseDuration(raw)
710		if err != nil || d <= 0 {
711			return defaultWorktreeReapMaxAge
712		}
713		return d
714	}
