716	// projectHasRoutingConfig reports whether the project's .ddx/config.yaml pins a
717	// routing decision that should suppress DDx's zero-config powerClass inference.
718	// agent.endpoints alone is transport configuration (where providers live) and
719	// does NOT pin routing — leaving it on the suppression list caused no-flag work
720	// in projects with local endpoints to send an empty Policy and inherit
721	// Fizeau's default policy (which, with no DDx-supplied hint, scored Opus on
722	// ordinary implementation work; see ddx-e0b95b4a).
723	func projectHasRoutingConfig(projectRoot string) bool {
724		if projectRoot == "" {
725			return false
726		}
727		cfgPath := ddxroot.JoinProject(projectRoot, "config.yaml")
728		if _, err := os.Stat(cfgPath); err != nil {
729			return false
730		}
731		cfg, err := config.LoadWithWorkingDir(projectRoot)
732		if err != nil || cfg == nil || cfg.Agent == nil {
733			return false
734		}
735		a := cfg.Agent
736		return strings.TrimSpace(a.Model) != ""
737	}
