242	// lookupBead scans the childIndex (which holds every bead, keyed by parent
243	// ID with roots under "") for the bead with the given ID.
244	func lookupBead(childIndex map[string][]Bead, id string) (Bead, bool) {
245		if id == "" {
246			return Bead{}, false
247		}
248		for _, beads := range childIndex {
249			for _, b := range beads {
250				if b.ID == id {
251					return b, true
252				}
253			}
254		}
255		return Bead{}, false
256	}
