300	// openDepBlockers returns the dep-target beads that are not yet closed.
301	// A dep whose target is absent from the index is NOT treated as a blocker
302	// here; that case is classified by malformed_parent_or_dep_ref later.
303	func openDepBlockers(b Bead, childIndex map[string][]Bead) []Bead {
304		var out []Bead
305		for _, d := range b.Dependencies {
306			if d.DependsOnID == "" {
307				continue
308			}
309			target, ok := lookupBead(childIndex, d.DependsOnID)
310			if !ok {
311				continue
312			}
313			if target.Status != StatusClosed && target.Status != StatusCancelled {
314				out = append(out, target)
315			}
316		}
317		return out
318	}
