396	// detectDepCycle returns the IDs of a cycle reachable from start through
397	// the dep DAG (depIndex maps bead_id -> outgoing deps). Returns nil if no
398	// cycle reaches back to start.
399	func detectDepCycle(start string, depIndex map[string][]Dependency) []string {
400		if start == "" || len(depIndex) == 0 {
401			return nil
402		}
403		visited := map[string]bool{}
404		var path []string
405		var dfs func(node string) []string
406		dfs = func(node string) []string {
407			for _, p := range path {
408				if p == node {
409					idx := 0
410					for i, q := range path {
411						if q == node {
412							idx = i
413							break
414						}
415					}
416					cyc := append([]string(nil), path[idx:]...)
417					cyc = append(cyc, node)
418					return cyc
419				}
420			}
421			if visited[node] {
422				return nil
423			}
424			visited[node] = true
425			path = append(path, node)
426			for _, d := range depIndex[node] {
427				if d.DependsOnID == "" {
428					continue
429				}
430				if cyc := dfs(d.DependsOnID); cyc != nil {
431					return cyc
432				}
433			}
434			path = path[:len(path)-1]
435			return nil
436		}
437		return dfs(start)
438	}
