2417	func humanReviewBlockerPressure(beads []Bead) ([]HumanReviewBlockerPressure, int) {
2418		byID := make(map[string]Bead, len(beads))
2419		reverseDeps := make(map[string][]string, len(beads))
2420		for _, b := range beads {
2421			byID[b.ID] = b
2422			if !activeForDependencyPressure(b) {
2423				continue
2424			}
2425			for _, dep := range b.Dependencies {
2426				if dep.DependsOnID == "" {
2427					continue
2428				}
2429				reverseDeps[dep.DependsOnID] = append(reverseDeps[dep.DependsOnID], b.ID)
2430			}
2431		}
2432	
2433		var blockers []HumanReviewBlockerPressure
2434		totalBlocked := map[string]struct{}{}
2435		for _, b := range beads {
2436			if !isHumanReviewBlocker(b) {
2437				continue
2438			}
2439			seen := map[string]struct{}{}
2440			var walk func(string)
2441			walk = func(id string) {
2442				for _, childID := range reverseDeps[id] {
2443					if childID == b.ID {
2444						continue
2445					}
2446					child, ok := byID[childID]
2447					if !ok || !activeForDependencyPressure(child) {
2448						continue
2449					}
2450					if _, exists := seen[childID]; exists {
2451						continue
2452					}
2453					seen[childID] = struct{}{}
2454					totalBlocked[childID] = struct{}{}
2455					walk(childID)
2456				}
2457			}
2458			walk(b.ID)
2459			if len(seen) == 0 {
2460				// A proposed/needs-human bead with no active downstream is operator
2461				// attention only; it does not contribute to HumanReviewBlockers.
2462				continue
2463			}
2464			blockers = append(blockers, HumanReviewBlockerPressure{
2465				ID:                     b.ID,
2466				Title:                  b.Title,
2467				Priority:               b.Priority,
2468				DownstreamBlockedCount: len(seen),
2469			})
2470		}
2471	
2472		sort.SliceStable(blockers, func(i, j int) bool {
2473			if blockers[i].Priority != blockers[j].Priority {
2474				return blockers[i].Priority < blockers[j].Priority
2475			}
2476			return blockers[i].ID < blockers[j].ID
2477		})
2478		return blockers, len(totalBlocked)
2479	}
