2490		for _, label := range b.Labels {
2491			switch label {
2492			case LabelNeedsHuman, LabelNeedsInvestigation, LabelNoChangesUnverified, LabelNoChangesUnjustified:
2493				return true
2494			}
2495		}
2496		return false
2497	}
