18	// AutoDecomposeEpicError indicates why an epic failed the precondition gates.
19	type AutoDecomposeEpicError struct {
20		Reason  string
21		Details string
22	}
23	
24	func (e *AutoDecomposeEpicError) Error() string {
25		if e.Details != "" {
26			return fmt.Sprintf("auto_decompose_epic: %s: %s", e.Reason, e.Details)
27		}
28		return fmt.Sprintf("auto_decompose_epic: %s", e.Reason)
29	}
