31	// AutoDecomposeEpic dispatches a preclaim decomposer for a genuinely undecomposed
32	// epic after validating every precondition. On precondition failure, returns
33	// a typed AutoDecomposeEpicError and increments the per-bead auto_decompose_attempted
34	// event count. On success, returns (DecomposeResult, nil). On decomposer failure,
35	// sets a 15m execution cooldown, emits auto_decompose_failed, and on the 3rd
36	// cumulative failure also emits auto_remediation_exhausted.
37	func AutoDecomposeEpic(
38		ctx context.Context,
39		store ExecuteBeadLoopStore,
40		runner AgentRunner,
41		rcfg config.ResolvedConfig,
42		projectRoot string,
43		beadID string,
44	) (DecomposeResult, error) {
45		b, err := store.Get(ctx, beadID)
46		if err != nil {
47			return DecomposeResult{Failed: true, Reason: "store_error"}, fmt.Errorf("load bead: %w", err)
48		}
49	
50		// 1. IssueType must be "epic"
51		issueType := strings.ToLower(strings.TrimSpace(b.IssueType))
52		if issueType != "epic" {
53			incrementAutoDecomposeAttempted(store, beadID, "not_epic")
54			return DecomposeResult{}, &AutoDecomposeEpicError{
55				Reason:  "not_epic",
56				Details: fmt.Sprintf("IssueType=%q, want epic", b.IssueType),
57			}
58		}
59	
60		// 2. totalChildCount must be 0; also check we're not in EpicClosureCandidate bucket
61		totalChildren, openChildren, err := countChildren(store, ctx, beadID)
62		if err != nil {
63			return DecomposeResult{Failed: true, Reason: "index_error"}, err
64		}
65		if totalChildren > 0 {
66			incrementAutoDecomposeAttempted(store, beadID, "has_children")
67			return DecomposeResult{}, &AutoDecomposeEpicError{
68				Reason:  "has_children",
69				Details: fmt.Sprintf("totalChildCount=%d, want 0", totalChildren),
70			}
71		}
72		// If epic has children and none are open, it's in the closure-candidate bucket
73		if totalChildren > 0 && openChildren == 0 {
74			incrementAutoDecomposeAttempted(store, beadID, "in_closure_candidate")
75			return DecomposeResult{}, &AutoDecomposeEpicError{
76				Reason:  "in_closure_candidate",
77				Details: "bead is in EpicClosureCandidate bucket",
78			}
79		}
80	
81		// 3. No open dep_blocked_by or closed_or_missing_parent diagnoses
82		allBeads := getAllBeads(store, ctx)
83		childIndex := buildChildIndex(allBeads)
84		openChildIndex := buildOpenChildIndex(allBeads)
85		depIndex := buildDepIndex(allBeads)
86	
87		blockReason := bead.Diagnose(
88			*b,
89			childIndex,
90			openChildIndex,
91			depIndex,
92		)
93		if blockReason.Code == bead.ReasonDepBlockedBy || blockReason.Code == bead.ReasonClosedOrMissingParent {
94			incrementAutoDecomposeAttempted(store, beadID, "dep_blocked")
95			return DecomposeResult{}, &AutoDecomposeEpicError{
96				Reason:  "dep_blocked",
97				Details: blockReason.Detail,
98			}
99		}
100	
101		// 4. No labels in {manual-hold, no-auto-decompose, container}
102		for _, label := range b.Labels {
103			switch label {
104			case "manual-hold", "no-auto-decompose", "container":
105				incrementAutoDecomposeAttempted(store, beadID, "override_label")
106				return DecomposeResult{}, &AutoDecomposeEpicError{
107					Reason:  "override_label",
108					Details: fmt.Sprintf("label=%q", label),
109				}
110			}
111		}
112	
113		// 5. Description must have PROBLEM and PROPOSED FIX sections, at least one AC,
114		// and at least one spec:/area: label
115		if err := validateEpicDescription(b); err != nil {
116			incrementAutoDecomposeAttempted(store, beadID, "malformed_description")
117			return DecomposeResult{}, &AutoDecomposeEpicError{
118				Reason:  "malformed_description",
119				Details: err.Error(),
120			}
121		}
122	
123		// 6. auto_decompose_attempted count < 3
124		attemptCount := countAutoDecomposeAttempts(store, beadID)
125		if attemptCount >= 3 {
126			incrementAutoDecomposeAttempted(store, beadID, "attempt_cap_reached")
127			return DecomposeResult{}, &AutoDecomposeEpicError{
128				Reason:  "attempt_cap_reached",
129				Details: fmt.Sprintf("attemptCount=%d, cap=3", attemptCount),
130			}
131		}
132	
133		// 7. No active execution cooldown
134		if hasActiveCooldown(b) {
135			incrementAutoDecomposeAttempted(store, beadID, "active_cooldown")
136			return DecomposeResult{}, &AutoDecomposeEpicError{
137				Reason:  "active_cooldown",
138				Details: extraStringValFromExtra(b.Extra, bead.ExtraRetryAfter),
139			}
140		}
141	
142		// All preconditions passed; dispatch runPreClaimDecomposer
143		decomp, dispatchErr := runPreClaimDecomposer(ctx, store, runner, rcfg, projectRoot, beadID)
144		if dispatchErr != nil || decomp == nil {
145			// Decomposition failed; set cooldown and emit event
146			reason := "decomposer_error"
147			if dispatchErr != nil {
148				reason = dispatchErr.Error()
149			}
150			cooldownUntil := time.Now().UTC().Add(15 * time.Minute)
151			_ = store.SetExecutionCooldown(
152				beadID,
153				cooldownUntil,
154				autoDecomposeFailedEventKind,
155				fmt.Sprintf("decomposer failed: %s", reason),
156				"",
157			)
158			_ = store.AppendEvent(beadID, bead.BeadEvent{
159				Kind:      autoDecomposeFailedEventKind,
160				Summary:   fmt.Sprintf("decomposition failed: %s", reason),
161				Body:      fmt.Sprintf(`{"reason":"%s"}`, reason),
162				Actor:     "ddx work",
163				Source:    "ddx work",
164				CreatedAt: time.Now().UTC(),
165			})
166	
167			// On 3rd cumulative failure, emit auto_remediation_exhausted
168			if attemptCount+1 >= 3 {
169				_ = store.AppendEvent(beadID, bead.BeadEvent{
170					Kind:      autoRemediationExhaustedEventKind,
171					Summary:   "auto-decomposition attempts exhausted",
172					Body:      `{"reason":"auto_decompose_failed_3x"}`,
173					Actor:     "ddx work",
174					Source:    "ddx work",
175					CreatedAt: time.Now().UTC(),
176				})
177			}
178	
179			return DecomposeResult{Failed: true, Reason: reason}, nil
180		}
181	
182		// Success: create child beads from the decomposition, set execution-eligible=false
183		childIDs := make([]string, 0, len(decomp.Children))
184		totalCost := 0.0
185	
186		for _, child := range decomp.Children {
187			nb := &bead.Bead{
188				Title:       child.Title,
189				Description: child.Description,
190				Acceptance:  child.Acceptance,
191				Labels:      append([]string(nil), child.Labels...),
192				Parent:      beadID,
193			}
194			if err := store.Create(ctx, nb); err != nil {
195				return DecomposeResult{Failed: true, Reason: "child_creation_failed"}, err
196			}
197			childIDs = append(childIDs, nb.ID)
198		}
199	
200		// Set parent's execution-eligible to false
201		_ = store.Update(ctx, beadID, func(updated *bead.Bead) {
202			ensureBeadExtra(updated)
203			updated.Extra[bead.ExtraExecutionElig] = false
204		})
205	
206		// Emit auto_decompose_attempted event
207		body, _ := json.Marshal(decomposerEventBody{
208			ChildIDs: childIDs,
209			CostUSD:  totalCost,
210		})
211		_ = store.AppendEvent(beadID, bead.BeadEvent{
212			Kind:      autoDecomposeAttemptedEventKind,
213			Summary:   fmt.Sprintf("auto-decomposed into %s", strings.Join(childIDs, ", ")),
214			Body:      string(body),
215			Actor:     "ddx work",
216			Source:    "ddx work",
217			CreatedAt: time.Now().UTC(),
218		})
219	
220		return DecomposeResult{Failed: false, ChildIDs: childIDs, CostUSD: totalCost}, nil
221	}
