279	// countAutoDecomposeAttempts counts cumulative auto_decompose_attempted events
280	// (both successes and gate failures).
281	func countAutoDecomposeAttempts(store ExecuteBeadLoopStore, beadID string) int {
282		events, err := store.Events(beadID)
