319	// countChildren returns the total and open child counts for a bead.
320	func countChildren(store ExecuteBeadLoopStore, ctx context.Context, beadID string) (total, open int, err error) {
321		allBeads := getAllBeads(store, ctx)
322		for _, candidate := range allBeads {
323			if candidate.Parent == beadID {
324				total++
325				if candidate.Status != bead.StatusClosed && candidate.Status != bead.StatusCancelled {
326					open++
327				}
328			}
329		}
330		return total, open, nil
331	}
