// closeSuperseededBead closes xID as superseded by closedID, recording the
// standard superseded_close event and clearing any claim heartbeat. Shared by
// the in-Close cascade (cascadeAndWalkUp), the standalone cascade
// (cascadeCloseSuperseeded), and the out-of-band RunSupersededCascade so the
// three paths stay byte-identical.
func (s *Store) closeSuperseededBead(xID, closedID string) {
	_ = s.SetLifecycleStatus(xID, StatusClosed, LifecycleTransitionOptions{
		ManualClose: true,
		Reason:      fmt.Sprintf("cascade-close superseded by %s", closedID),
		Source:      "Store.Close.cascadeCloseSuperseeded",
	})
	_ = s.externalizeEvents(xID)
	_ = s.AppendEvent(xID, BeadEvent{
		Kind:      "superseded_close",
		Summary:   fmt.Sprintf("closed as superseded via %s", closedID),
		Body:      fmt.Sprintf("closed_by_cascade_of: %s\nreason: closed_as_superseded_via:%s", closedID, closedID),
		Source:    "Store.Close.cascadeCloseSuperseeded",
		CreatedAt: time.Now().UTC(),
	})
	_ = s.RemoveClaimHeartbeat(xID)
}

// RunSupersededCascade closes supersededID out of band when it is superseded by
// the already-closed supersederID and passes every cascade scope guard
// (canCascadeCloseSuperseeded). It runs the same scope-checked close used inside
// Close() so the idle-path auto-remediation can finish a supersession cascade
// that never fired. Returns (true, nil) only when supersededID was actually
// closed; (false, nil) when a guard blocks it. Idempotent — safe to re-run.
func (s *Store) RunSupersededCascade(supersededID, supersederID string) (bool, error) {
	all, err := s.ReadAll(context.Background())
	if err != nil {
		return false, err
	}
	x := findBeadByID(all, supersededID)
	if x == nil {
		return false, nil
	}
	if !s.canCascadeCloseSuperseeded(x, supersederID, all) {
		return false, nil
	}
	s.closeSuperseededBead(supersededID, supersederID)
	return true, nil
}

// RunClosureEvaluation runs the standard walk-up closure evaluation against
// beadID out of band: if beadID is an epic whose children are all terminal, or
// a dead-intermediate (execution-eligible=false) whose children are all
// terminal, it is auto-closed exactly as the in-Close walk-up would. Returns
// (true, nil) only when beadID transitioned to closed. Idempotent.
func (s *Store) RunClosureEvaluation(beadID string) (bool, error) {
	all, err := s.ReadAll(context.Background())
	if err != nil {
		return false, err
	}
	target := findBeadByID(all, beadID)
	if target == nil || target.Status == StatusClosed || target.Status == StatusCancelled {
		return false, nil
	}
	s.walkUpClosureCandidate(beadID, all, map[string]bool{})
	after, err := s.Get(context.Background(), beadID)
	if err != nil {
		return false, err
	}
	return after.Status == StatusClosed, nil
}

