// idleAutoRemediationResult counts the idle-path remediations attempted in one
// pass and the subset that changed bead state. TotalSucceeded > 0 means the
// loop should re-scan without sleeping.
type idleAutoRemediationResult struct {
	Counts         map[string]int
	TotalAttempted int
	TotalSucceeded int
}

// runIdleAutoRemediation diagnoses every non-ready bead surfaced in the empty
// execution queue (epics, dependency-waiting, operator-attention), fires the
// matching enabled remediator, and reports how many changed state. The caller
// re-scans without sleeping when TotalSucceeded > 0.
//
// Per FEAT-010 §Idle-Path Diagnosis and Auto-Remediation it never sleeps and
// performs at most one AutoDecomposeEpic dispatch per pass. Remediations only
// count as successes when the bead actually transitioned (closed / children
// filed), which guarantees the re-scan converges rather than looping.
func (w *ExecuteBeadWorker) runIdleAutoRemediation(
	ctx context.Context,
	runtime ExecuteBeadLoopRuntime,
	emit func(string, map[string]any),
) idleAutoRemediationResult {
	res := idleAutoRemediationResult{Counts: map[string]int{}}
	cfg := runtime.IdleAutoRemediation
	if !cfg.anyEnabled() {
		return res
	}
	rstore, ok := w.Store.(idleRemediationStore)
	if !ok {
		return res
	}
	diag, ok := w.Store.(readyDiagnoser)
	if !ok {
		return res
	}
	breakdown, err := diag.ReadyExecutionBreakdown()
	if err != nil {
		return res
	}
	all, err := rstore.ReadAll(ctx)
	if err != nil {
		return res
	}
	byID := make(map[string]bead.Bead, len(all))
	for _, b := range all {
		byID[b.ID] = b
	}
	childIndex := buildChildIndex(all)
	openChildIndex := buildOpenChildIndex(all)
	depIndex := buildDepIndex(all)

	// Candidate set: epics ∪ dependency-waiting ∪ operator-attention, deduped.
	seen := map[string]bool{}
	var candidates []string
	for _, group := range [][]string{breakdown.Epics, breakdown.DependencyWaiting, breakdown.ProposedOperatorAttention} {
		for _, id := range group {
			if id == "" || seen[id] {
				continue
			}
			seen[id] = true
			candidates = append(candidates, id)
		}
	}

	decomposeDispatched := false
	record := func(code bead.BlockReasonCode, beadID, action string) {
		res.Counts[string(code)]++
		res.TotalSucceeded++
		emit("loop.idle_remediation", map[string]any{
			"bead_id":      beadID,
			"block_reason": string(code),
			"action":       action,
		})
	}
	gate := func(beadID, detail string) {
		emit("loop.idle_diagnosis", map[string]any{
			"bead_id":      beadID,
			"block_reason": string(bead.ReasonGatedByBudgetOrCooldown),
			"detail":       detail,
		})
	}

	for _, id := range candidates {
		b, ok := byID[id]
		if !ok {
			continue
		}
		reason := bead.Diagnose(b, childIndex, openChildIndex, depIndex)
		switch reason.Code {
		case bead.ReasonSupersededPendingClose:
			if !cfg.AutoSupersedeClose {
				continue
			}
			superseder := ""
			if len(reason.CitedIDs) > 0 {
				superseder = reason.CitedIDs[0]
			}
			res.TotalAttempted++
			if closed, cerr := rstore.RunSupersededCascade(id, superseder); cerr == nil && closed {
				record(reason.Code, id, "superseded_cascade_close")
			}
		case bead.ReasonClosureCandidateMisclassified, bead.ReasonDeadIntermediateAllChildrenClosed:
			if !cfg.AutoClosureReclassify {
				continue
			}
			res.TotalAttempted++
			if closed, cerr := rstore.RunClosureEvaluation(id); cerr == nil && closed {
				record(reason.Code, id, "closure_evaluation_close")
			}
		case bead.ReasonGenuinelyNeedsDecomposition:
			if !cfg.AutoEpicDecompose {
				gate(id, "no-auto-epic-decompose")
				continue
			}
			if runtime.MaxRecoveryCostUSD <= 0 {
				gate(id, "max-recovery-cost")
				continue
			}
			if runtime.IdleAutoDecomposeHook == nil {
				continue
			}
			if decomposeDispatched {
				// At most one decompose dispatch per pass; the rest are handled
				// on subsequent idle passes.
				continue
			}
			decomposeDispatched = true
			res.TotalAttempted++
			dr, derr := runtime.IdleAutoDecomposeHook(ctx, id)
			if derr == nil && !dr.Failed && len(dr.ChildIDs) > 0 {
				record(reason.Code, id, "auto_decompose_epic")
			}
		default:
			// dead_intermediate_open_children_pending, epic_of_epic: recursion via
			// children handles them. All other codes have no idle-path action and
			// surface via `ddx work focus`.
		}
	}
	return res
}

