package agent

import (
	"bytes"
	"context"
	"strings"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// idleRemediationRcfg builds the standard sealed loop config used by the
// idle-path auto-remediation tests.
func idleRemediationRcfg(t *testing.T) config.ResolvedConfig {
	t.Helper()
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	return config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
}

// undecomposedEpic returns a childless, execution-ineligible epic that satisfies
// the genuinely_needs_decomposition diagnosis. execution-eligible=false keeps it
// out of the ready queue (so the loop reaches the idle path) while leaving it in
// the NotEligible breakdown bucket the idle pass sweeps.
func undecomposedEpic(id, title string) *bead.Bead {
	return &bead.Bead{
		ID:        id,
		Title:     title,
		IssueType: "epic",
		Status:    bead.StatusOpen,
		Priority:  1,
		Labels:    []string{"spec:FEAT-010", "area:agent"},
		Extra:     map[string]any{bead.ExtraExecutionElig: false},
	}
}

// TestWorkIdle_AutoRemediatesAndRescansWithoutSleep covers AC #3: a fixture with
// one mislabeled closure-candidate epic plus one supersession leftover is fully
// auto-resolved in a single loop iteration, emitting loop.auto_remediated and
// returning drained without sleeping or executing any bead.
func TestWorkIdle_AutoRemediatesAndRescansWithoutSleep(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	// Closure-candidate epic: epic with every child closed.
	epic := &bead.Bead{ID: "ddx-cc-epic", Title: "Closure candidate epic", IssueType: "epic", Status: bead.StatusOpen, Priority: 1}
	require.NoError(t, store.Create(epic))
	require.NoError(t, store.Create(&bead.Bead{ID: "ddx-cc-child", Title: "done child", Parent: epic.ID, Status: bead.StatusClosed}))

	// Supersession leftover: open bead superseded by an already-closed bead.
	superseder := &bead.Bead{ID: "ddx-sup-Y", Title: "superseder", Status: bead.StatusClosed}
	require.NoError(t, store.Create(superseder))
	leftover := &bead.Bead{ID: "ddx-sup-X", Title: "superseded leftover", Status: bead.StatusOpen,
		Extra: map[string]any{"superseded-by": superseder.ID}}
	require.NoError(t, store.Create(leftover))

	worker := &ExecuteBeadWorker{
		Store: store,
