// TestWorkIdle_AutoDecomposeUndecomposedEpic covers AC #4: a genuinely
// undecomposed epic triggers exactly one AutoDecomposeEpic dispatch; the hook
// files children and marks the parent execution-ineligible, and the loop
// re-scans and picks one freshly-filed child.
func TestWorkIdle_AutoDecomposeUndecomposedEpic(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	epic := undecomposedEpic("ddx-undec-epic", "Undecomposed epic")
	require.NoError(t, store.Create(epic))

	var dispatches int
	hook := func(ctx context.Context, beadID string) (DecomposeResult, error) {
		dispatches++
		childIDs := []string{beadID + "-c1", beadID + "-c2"}
		for _, cid := range childIDs {
			require.NoError(t, store.Create(&bead.Bead{ID: cid, Title: "child " + cid, Parent: beadID, Status: bead.StatusOpen, Priority: 1}))
		}
		require.NoError(t, store.Update(beadID, func(b *bead.Bead) {
			if b.Extra == nil {
				b.Extra = map[string]any{}
			}
			b.Extra[bead.ExtraExecutionElig] = false
		}))
		return DecomposeResult{ChildIDs: childIDs}, nil
	}

	var executed []string
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			executed = append(executed, beadID)
			return ExecuteBeadReport{BeadID: beadID, Status: ExecuteBeadStatusSuccess, Detail: "ok", SessionID: "sess", ResultRev: "deadbeef"}, nil
		}),
	}

	var sink bytes.Buffer
	result, err := worker.Run(context.Background(), idleRemediationRcfg(t), ExecuteBeadLoopRuntime{
		Once:                  true,
		EventSink:             &sink,
		IdleAutoRemediation:   IdleAutoRemediationConfig{AutoEpicDecompose: true},
		IdleAutoDecomposeHook: hook,
		MaxRecoveryCostUSD:    2.0,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	assert.Equal(t, 1, dispatches, "exactly one AutoDecomposeEpic dispatch")
	require.Len(t, executed, 1, "loop re-scans and picks exactly one child")
	picked, err := store.Get(executed[0])
	require.NoError(t, err)
	assert.Equal(t, epic.ID, picked.Parent, "the executed bead is a child of the decomposed epic")

	gotEpic, err := store.Get(epic.ID)
	require.NoError(t, err)
	eligible, set := bead.LifecycleExecutionEligibleForTest(*gotEpic)
	assert.True(t, set && !eligible, "parent epic must be marked execution-eligible=false")
}

