// TestWorkIdle_AtMostOneDecomposePerIteration covers AC #6: with three
// undecomposed epics, each idle pass dispatches exactly one decompose and
// subsequent passes handle the rest. The decompose hook files non-ready
// children so the loop stays in the idle path across passes.
func TestWorkIdle_AtMostOneDecomposePerIteration(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())
	for _, id := range []string{"ddx-e1", "ddx-e2", "ddx-e3"} {
		require.NoError(t, store.Create(undecomposedEpic(id, "Epic "+id)))
	}

	var dispatched []string
	hook := func(ctx context.Context, beadID string) (DecomposeResult, error) {
		dispatched = append(dispatched, beadID)
		cid := beadID + "-child"
		// Children are blocked (non-ready) so the queue stays idle and the loop
		// runs another remediation pass instead of claiming a child.
		require.NoError(t, store.Create(&bead.Bead{
			ID: cid, Title: "child of " + beadID, Parent: beadID, Status: bead.StatusBlocked,
			Extra: map[string]any{bead.ExtraLifecycleExternalBlockerReason: "awaiting decomposition detail"},
		}))
		require.NoError(t, store.Update(beadID, func(b *bead.Bead) {
			if b.Extra == nil {
				b.Extra = map[string]any{}
			}
			b.Extra[bead.ExtraExecutionElig] = false
		}))
		return DecomposeResult{ChildIDs: []string{cid}}, nil
	}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatalf("executor must not run for non-ready children (got %s)", beadID)
			return ExecuteBeadReport{}, nil
		}),
	}

	var sink bytes.Buffer
	result, err := worker.Run(context.Background(), idleRemediationRcfg(t), ExecuteBeadLoopRuntime{
		EventSink:             &sink,
		IdleAutoRemediation:   IdleAutoRemediationConfig{AutoEpicDecompose: true},
		IdleAutoDecomposeHook: hook,
		MaxRecoveryCostUSD:    10.0,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	assert.Len(t, dispatched, 3, "all three epics are decomposed across the drain")
	// One loop.auto_remediated event per pass proves at most one decompose per
	// iteration (a single multi-decompose pass would emit only one event).
	assert.Equal(t, 3, strings.Count(sink.String(), "loop.auto_remediated"),
		"each decompose must be dispatched in its own idle pass")
}

// TestWorkIdle_OverrideFlagSuppressesDecompose covers AC #7: with
// --no-auto-epic-decompose set, no dispatch occurs even though preconditions
// pass; the bead is surfaced as gated_by_budget_or_cooldown with detail
// "no-auto-epic-decompose".
func TestWorkIdle_OverrideFlagSuppressesDecompose(t *testing.T) {
